pub fn PlaySongNI(cpu: &mut Cpu) {
    setaux(cpu);
    crate::ext::xminit(cpu);
    loop {
        crate::ext::xmplay(cpu);
        let _o: u8 = 0x00;
        cpu.flags.c = cpu.reg.a >= _o;
        cpu.flags.z = cpu.reg.a == _o;
        cpu.flags.n = (cpu.reg.a.wrapping_sub(_o) >> 7) != 0;
        if !(cpu.reg.a != 0x00) {
            break;
        }
    }
    return;
}

pub fn PlaySongI(cpu: &mut Cpu) {
    let mut pc: u32 = 0;
    loop {
        match pc {
            0 => {
                setaux(cpu);
                if cpu.flags.z {
                    pc = 12;
                } else {
                    pc = 1;
                }
            }
            1 => {
                cpu.reg.y = cpu.reg.a;
                cpu.reg.a = cpu.mem[sym::musicon];
                cpu.reg.a &= cpu.mem[sym::soundon];
                if cpu.reg.a == 0x00 {
                    pc = 5;
                } else {
                    pc = 2;
                }
            }
            2 => {
                cpu.reg.a = cpu.reg.y;
                crate::ext::xminit(cpu);
                pc = 7;
            }
            3 => {
                StartGame_3f(cpu);
                crate::ext::xmplay(cpu);
                let _o: u8 = 0x00;
                cpu.flags.c = cpu.reg.a >= _o;
                cpu.flags.z = cpu.reg.a == _o;
                cpu.flags.n = (cpu.reg.a.wrapping_sub(_o) >> 7) != 0;
                if cpu.reg.a != 0x00 {
                    pc = 7;
                } else {
                    pc = 4;
                }
            }
            4 => {
                return;
            }
            5 => {
                cpu.reg.a = cpu.reg.x;
                pc = 6;
            }
            6 => {
                pc = 7;
            }
            7 => {
                cpu.mem[sym::pausetemp] = cpu.reg.a;
                cpu.reg.y = 0x02;
                pc = 8;
            }
            8 => {
                cpu.reg.x = 0x00;
                pc = 9;
            }
            9 => {
                StartGame_3f(cpu);
                cpu.reg.x = cpu.reg.x.wrapping_sub(1);
                if cpu.reg.x != 0x00 {
                    pc = 9;
                } else {
                    pc = 10;
                }
            }
            10 => {
                cpu.reg.y = cpu.reg.y.wrapping_sub(1);
                if cpu.reg.y != 0x00 {
                    pc = 8;
                } else {
                    pc = 11;
                }
            }
            11 => {
                cpu.reg.a = cpu.mem[sym::pausetemp];
                cpu.flags.c = true;
                let _r = (cpu.reg.a as u16) + (!0x01_u8) as u16 + (cpu.flags.c as u16);
                cpu.reg.a = _r as u8;
                cpu.flags.c = (_r >> 8) != 0;
                if cpu.reg.a != 0x00 {
                    pc = 7;
                } else {
                    pc = 12;
                }
            }
            12 => {
                return;
            }
            _ => unreachable!(),
        }
    }
}

#[doc(alias = ":loop")]
pub fn tpause(cpu: &mut Cpu) {
    let mut pc: u32 = 0;
    loop {
        match pc {
            0 => {
                cpu.mem[sym::pausetemp] = cpu.reg.a;
                cpu.reg.y = 0x02;
                pc = 1;
            }
            1 => {
                cpu.reg.x = 0x00;
                pc = 2;
            }
            2 => {
                StartGame_3f(cpu);
                cpu.reg.x = cpu.reg.x.wrapping_sub(1);
                if cpu.reg.x != 0x00 {
                    pc = 2;
                } else {
                    pc = 3;
                }
            }
            3 => {
                cpu.reg.y = cpu.reg.y.wrapping_sub(1);
                if cpu.reg.y != 0x00 {
                    pc = 1;
                } else {
                    pc = 4;
                }
            }
            4 => {
                cpu.reg.a = cpu.mem[sym::pausetemp];
                cpu.flags.c = true;
                let _r = (cpu.reg.a as u16) + (!0x01_u8) as u16 + (cpu.flags.c as u16);
                cpu.reg.a = _r as u8;
                cpu.flags.c = (_r >> 8) != 0;
                if cpu.reg.a != 0x00 {
                    pauseNI(cpu);
                    return;
                } else {
                    pc = 5;
                }
            }
            5 => {
                return;
            }
            _ => unreachable!(),
        }
    }
}

pub fn error(cpu: &mut Cpu) {
    driveoff(cpu);
    crate::ext::prompt(cpu);
    driveon(cpu);
    return;
}

pub fn _5dlsub(cpu: &mut Cpu) {
    let mut pc: u32 = 0;
    loop {
        match pc {
            0 => {
                cpu.mem[sym::track] = cpu.reg.a;
                pc = 1;
            }
            1 => {
                crate::ext::rw18(cpu);
                if !cpu.flags.c {
                    pc = 3;
                } else {
                    pc = 2;
                }
            }
            2 => {
                error(cpu);
                pc = 1;
            }
            3 => {
                crate::ext::rw18(cpu);
                crate::ext::rw18(cpu);
                crate::ext::rw18(cpu);
                crate::ext::rw18(cpu);
                return;
            }
            _ => unreachable!(),
        }
    }
}
